class Solution:
    def smallestStringWithSwaps(self, s, pairs):
        n = len(s)
        adj = [[] for _ in range(n)]
        for a, b in pairs:
            adj[a].append(b)
            adj[b].append(a)
        seen = [False] * n
        res = list(s)
        for i in range(n):
            if seen[i]:
                continue
            stack = [i]
            seen[i] = True
            comp = []
            while stack:
                u = stack.pop()
                comp.append(u)
                for v in adj[u]:
                    if not seen[v]:
                        seen[v] = True
                        stack.append(v)
            idxs = sorted(comp)
            chars = sorted(s[j] for j in comp)
            for k, j in enumerate(idxs):
                res[j] = chars[k]
        return ''.join(res)

