class Solution:
    def smallestStringWithSwaps(self, s, pairs):
        n = len(s)
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        for a, b in pairs:
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        from collections import defaultdict
        groups = defaultdict(list)
        for i in range(n):
            groups[find(i)].append(i)
        res = list(s)
        for idxs in groups.values():
            chars = sorted(s[i] for i in idxs)
            for k, i in enumerate(sorted(idxs)):
                res[i] = chars[k]
        return ''.join(res)

